def lcs_ratio_target(a,b):
    # longest common substring length / len(target) where b is target
    L = lcs_length(a,b)
    lentarget = len(normalize_ar(b))
    if lentarget==0:
        return 0.0
    return L / lentarget

def similarity_candidate(candidate, target):
    return max(token_f1(candidate,target), lcs_ratio_target(candidate,target))

